BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?pkg ?name ?ownedElem ?ownedName WHERE {
  ?pkg vocab:NamedElement_name ?name .
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("Roll-up Pattern"))) 
  OPTIONAL { ?pkg vocab:Element_ownedElement ?ownedElem .
             ?ownedElem vocab:NamedElement_name ?ownedName }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name ?comment ?body WHERE {
  ?elem vocab:NamedElement_name ?name .
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("RollUp"))) 
  OPTIONAL { ?elem vocab:Element_ownedComment ?comment .
             ?comment vocab:Comment_body ?body }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?inst ?name ?classifier ?classifierName WHERE {
  ?inst vocab:NamedElement_name ?name .
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("ErrorRollUpPatternElement"))) 
  OPTIONAL { ?inst vocab:InstanceSpecification_classifier ?classifier .
             ?classifier vocab:NamedElement_name ?classifierName }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?prop ?value ?valueName ?valueType WHERE {
  ?elem vocab:NamedElement_name "RootSumSquared" .
  ?elem ?prop ?value .
  FILTER(CONTAINS(STR(?prop), "Element_ownedElement")) .
  OPTIONAL { ?value vocab:NamedElement_name ?valueName }
  OPTIONAL { ?value rdf:type ?valueType }
}
LIMIT 50
